index 0000000..1c53cc3
--- /dev/null
+++ b/Caffe/model/PWC-Net_plus/PWC-Net_plus_kitti/model/test.prototxt
@@ -0,0 +1,2788 @@
+layer {
+  name: "Image1"
+  type: "ImageData"
+  top: "img0"
+  top: "dummy1" 
+  image_data_param {
+    source: "tmp/img1.txt"
+    batch_size: 1
+  }
+}
+layer {
+  name: "Image2"
+  type: "ImageData"
+  top: "img1"
+  top: "dummy2" 
+  image_data_param {
+    source: "tmp/img2.txt"
+    batch_size: 1
+  }
+}
+layer {
+  name: "dummy1" 
+  type: "Silence" 
+  bottom: "dummy1" 
+}
+
+layer {
+  name: "dummy2"
+  type: "Silence"
+  bottom: "dummy2"
+}
+
+
+layer {
+  name: "Eltwise2"
+  type: "Eltwise"
+  bottom: "img1"
+  top: "img1s"
+  eltwise_param {
+    operation: SUM
+    coeff: 0.00392156862745
+  }
+}
+layer {
+  name: "Eltwise1"
+  type: "Eltwise"
+  bottom: "img0"
+  top: "img0s"
+  eltwise_param {
+    operation: SUM
+    coeff: 0.00392156862745
+  }
+}
+layer {
+  name: "img0s_aug"
+  type: "DataAugmentation"
+  bottom: "img0s"
+  top: "img0_nomean"
+  augmentation_param {
+    augment_during_test: true
+    recompute_mean: 1000
+    mean_per_pixel: false
+    crop_width: $TARGET_WIDTH
+    crop_height: $TARGET_HEIGHT
+  }
+}
+layer {
+  name: "img1s_aug"
+  type: "DataAugmentation"
+  bottom: "img1s"
+  top: "img1_nomean"
+  augmentation_param {
+    augment_during_test: true
+    recompute_mean: 1000
+    mean_per_pixel: false
+    crop_width: $TARGET_WIDTH
+    crop_height: $TARGET_HEIGHT
+  }
+}
+layer {
+  name: "Resample1"
+  type: "Resample"
+  bottom: "img0_nomean"
+  top: "img0_nomean_resize"
+  resample_param {
+    width: $ADAPTED_WIDTH
+    height: $ADAPTED_HEIGHT
+    type: LINEAR
+    antialias: true
+  }
+}
+
+layer {
+  name: "Resample2"
+  type: "Resample"
+  bottom: "img1_nomean"
+  top: "img1_nomean_resize"
+  resample_param {
+    width: $ADAPTED_WIDTH
+    height: $ADAPTED_HEIGHT
+    type: LINEAR
+    antialias: true
+  }
+}
+
+# generate image pyramid
+
+layer {
+  name: "py-conv1"
+  type: "Convolution"
+  bottom: "img0_nomean_resize"
+  bottom: "img1_nomean_resize"
+  top: "image0_1_a"
+  top: "image1_1_a"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 16
+    pad: 1
+    kernel_size: 3
+    stride: 2
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU1-0"
+  type: "ReLU"
+  bottom: "image0_1_a"
+  top: "image0_1_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU1-1"
+  type: "ReLU"
+  bottom: "image1_1_a"
+  top: "image1_1_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+
+layer {
+  name: "py-conv1-b"
+  type: "Convolution"
+  bottom: "image0_1_a"
+  bottom: "image1_1_a"
+  top: "image0_1"
+  top: "image1_1"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 16
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU1-b-0" # pyramid level - convolution level - image index
+  type: "ReLU"
+  bottom: "image0_1"
+  top: "image0_1"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU1-b-1"
+  type: "ReLU"
+  bottom: "image1_1"
+  top: "image1_1"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv2"
+  type: "Convolution"
+  bottom: "image0_1"
+  bottom: "image1_1"
+  top: "image0_2_a"
+  top: "image1_2_a"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 32
+    pad: 1
+    kernel_size: 3
+    stride: 2
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU2-0"
+  type: "ReLU"
+  bottom: "image0_2_a"
+  top: "image0_2_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU2-1"
+  type: "ReLU"
+  bottom: "image1_2_a"
+  top: "image1_2_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv2-b"
+  type: "Convolution"
+  bottom: "image0_2_a"
+  bottom: "image1_2_a"
+  top: "image0_2"
+  top: "image1_2"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 32
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU2-b-0"
+  type: "ReLU"
+  bottom: "image0_2"
+  top: "image0_2"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU2-b-1"
+  type: "ReLU"
+  bottom: "image1_2"
+  top: "image1_2"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv3"
+  type: "Convolution"
+  bottom: "image0_2"
+  bottom: "image1_2"
+  top: "image0_3_a"
+  top: "image1_3_a"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 64
+    pad: 1
+    kernel_size: 3
+    stride: 2
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU3-0"
+  type: "ReLU"
+  bottom: "image0_3_a"
+  top: "image0_3_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU3-1"
+  type: "ReLU"
+  bottom: "image1_3_a"
+  top: "image1_3_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv3-b"
+  type: "Convolution"
+  bottom: "image0_3_a"
+  bottom: "image1_3_a"
+  top: "image0_3"
+  top: "image1_3"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 64
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU3-b-0"
+  type: "ReLU"
+  bottom: "image0_3"
+  top: "image0_3"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU3-b-1"
+  type: "ReLU"
+  bottom: "image1_3"
+  top: "image1_3"
