+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv4"
+  type: "Convolution"
+  bottom: "image0_3"
+  bottom: "image1_3"
+  top: "image0_4_a"
+  top: "image1_4_a"
