+    num_output: 96
+    pad: 1
+    kernel_size: 3
+    stride: 2
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU4-0"
+  type: "ReLU"
+  bottom: "image0_4_a"
+  top: "image0_4_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU4-1"
+  type: "ReLU"
+  bottom: "image1_4_a"
+  top: "image1_4_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv4-b"
+  type: "Convolution"
+  bottom: "image0_4_a"
+  bottom: "image1_4_a"
+  top: "image0_4"
+  top: "image1_4"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 96
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU4-b-0"
+  type: "ReLU"
+  bottom: "image0_4"
+  top: "image0_4"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU4-b-1"
+  type: "ReLU"
+  bottom: "image1_4"
+  top: "image1_4"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv5"
+  type: "Convolution"
+  bottom: "image0_4"
+  bottom: "image1_4"
+  top: "image0_5_a"
+  top: "image1_5_a"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 128
+    pad: 1
+    kernel_size: 3
+    stride: 2
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU5-0"
+  type: "ReLU"
+  bottom: "image0_5_a"
+  top: "image0_5_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU5-1"
+  type: "ReLU"
+  bottom: "image1_5_a"
+  top: "image1_5_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+
+layer {
+  name: "py-conv5-b"
+  type: "Convolution"
+  bottom: "image0_5_a"
+  bottom: "image1_5_a"
+  top: "image0_5"
+  top: "image1_5"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 128
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU5-b-0"
+  type: "ReLU"
+  bottom: "image0_5"
+  top: "image0_5"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU5-b-1"
+  type: "ReLU"
+  bottom: "image1_5"
+  top: "image1_5"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+
+layer {
+  name: "py-conv6"
+  type: "Convolution"
+  bottom: "image0_5"
+  bottom: "image1_5"
+  top: "image0_6_a"
+  top: "image1_6_a"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 196
+    pad: 1
+    kernel_size: 3
+    stride: 2
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
+layer {
+  name: "py-ReLU6-0"
+  type: "ReLU"
+  bottom: "image0_6_a"
+  top: "image0_6_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU6-1"
+  type: "ReLU"
+  bottom: "image1_6_a"
+  top: "image1_6_a"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "py-conv6-b"
+  type: "Convolution"
+  bottom: "image0_6_a"
+  bottom: "image1_6_a"
+  top: "image0_6"
+  top: "image1_6"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 196
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
+    engine: CUDNN
+  }
+}
