+  relu_param {
+    negative_slope: 0.1
+  }
+}
+layer {
+  name: "py-ReLU6-b-1"
+  type: "ReLU"
+  bottom: "image1_6"
+  top: "image1_6"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+
+layer {
+  name: "corr6"
+  type: "Correlation"
+  bottom: "image0_6"
+  bottom: "image1_6"
+  top: "corr6"
+  correlation_param {
+    pad: 4
+    kernel_size: 1
+    max_displacement: 4
+    stride_1: 1
+    stride_2: 1
+  }
+}
+layer {
+  name: "corReLU6"
+  type: "ReLU"
+  bottom: "corr6"
+  top: "corr6"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+# decode flow  6
+
+layer {
+  name: "conv6"
+  type: "Convolution"
+  bottom: "corr6"
+  top: "conv6"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 128
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
+      type: "constant"
+    }
