+}
+
+layer {
+  name: "dense-Concat6"
+  type: "Concat"
+  bottom: "corr6"
+  bottom: "conv6"
+  top: "dense-concat6"
+}
+
+layer {
+  name: "conv6-1"
+  type: "Convolution"
+  bottom: "dense-concat6"
+  top: "conv6-1"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 128
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
