+  name: "ReLU6-2"
+  type: "ReLU"
+  bottom: "conv6-2"
+  top: "conv6-2"
+  relu_param {
+    negative_slope: 0.1
+  }
+}
+
+layer {
+  name: "dense-Concat6-2"
+  type: "Concat"
+  bottom: "dense-concat6-1"
+  bottom: "conv6-2"
+  top: "dense-concat6-2"
+}
+
+layer {
+  name: "conv6-3"
+  type: "Convolution"
+  bottom: "dense-concat6-2"
+  top: "conv6-3"
+  param {
+    lr_mult: 1
+    decay_mult: 1
+  }
+  param {
+    lr_mult: 1
+    decay_mult: 0
+  }
+  convolution_param {
+    num_output: 64
+    pad: 1
+    kernel_size: 3
+    stride: 1
+    weight_filler {
+      type: "msra"
+    }
+    bias_filler {
